import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms'; // مهمة جداً عشان الـ Modal والـ Forms

@Component({
  selector: 'app-doctors-management',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './doctors-management.component.html',
  styleUrls: ['./doctors-management.component.scss']
})
export class DoctorsManagementComponent implements OnInit {

  // مصفوفة الدكاترة
  doctorsList = [
    { id: 1, name: 'Dr. Sarah Magdy', dept: 'Cardiology', email: 'sarah.ahmed@medilab.com', phone: '012801990', status: 'Active', photo: 'assets/img/doctor-placeholder.jpg' },
    { id: 2, name: 'Dr. Michael', dept: 'Pediatrics', email: 'mark.m@medilab.com', phone: '0128888444', status: 'Active', photo: 'assets/img/doctor-placeholder2.jpg' }
  ];

  // كائن لتخزين بيانات الدكتور الجديد اللي هنضيفه من الـ Modal
  newDoctor = { name: '', dept: 'Cardiology', email: '', phone: '', status: 'Active' };

  constructor() {}

  ngOnInit(): void {}

  // ➕ دالة إضافة دكتور جديد
  addDoctor(): void {
    if (this.newDoctor.name && this.newDoctor.email) {
      this.doctorsList.push({
        id: Date.now(), // ID عشوائي مؤقت
        name: this.newDoctor.name,
        dept: this.newDoctor.dept,
        email: this.newDoctor.email,
        phone: this.newDoctor.phone,
        status: this.newDoctor.status,
        photo: 'assets/img/doctor-placeholder.jpg' // صورة افتراضية
      });

      // ريستارت للفورم بعد الإضافة
      this.newDoctor = { name: '', dept: 'Cardiology', email: '', phone: '', status: 'Active' };

      // كود جافاسكريبت صغير لقفل الـ Modal أوتوماتيك بعد الضغط
      const modalCloseBtn = document.getElementById('closeModalBtn');
      if (modalCloseBtn) modalCloseBtn.click();
    }
  }

  // 🗑️ دالة حذف الدكتور عند الضغط على سلة المهملات
  deleteDoctor(id: number): void {
    if (confirm('هل أنتِ متأكدة من حذف هذا الطبيب؟')) {
      this.doctorsList = this.doctorsList.filter(doc => doc.id !== id);
    }
  }
}
